import React, { useState, useEffect } from 'react';
import './App.css';

interface Deployment {
  customer: string;
  project: string;
  environment: string;
  branch: string;
  commit: string;
  user: string;
  email: string;
  releaseDate: string;
  buildDate: string;
}

interface ApiResponse {
  pageNumber: number;
  pageSize: number;
  total: number;
  results: Deployment[];
}

type Environment = 'PROD' | 'STAGE' | 'TEST';

// CONFIGURATION: Update these with your actual GitHub Org and Repo name
// If you have multiple repos, you might need logic to map 'project' to 'repo'.
// For now, assuming a single repo or a generic pattern.
const GITHUB_ORG = "keros-keros-dev"; // CHANGE THIS
const GITHUB_REPO = "KNimbus-2017"; // CHANGE THIS (or remove if you use a dynamic mapping)

function App() {
  const [deployments, setDeployments] = useState<Deployment[]>([]);
  const [filteredDeployments, setFilteredDeployments] = useState<Deployment[]>([]);
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedEnv, setSelectedEnv] = useState<Environment>('PROD');

  const getLatestDeployments = (data: Deployment[]): Deployment[] => {
    const map = new Map<string, Deployment>();
    data.forEach((dep) => {
      const key = `$${dep.customer}-$${dep.project}-${dep.environment}`;
      const existing = map.get(key);
      if (!existing || new Date(dep.releaseDate) > new Date(existing.releaseDate)) {
        map.set(key, dep);
      }
    });
    return Array.from(map.values()).sort(
      (a, b) => new Date(b.releaseDate).getTime() - new Date(a.releaseDate).getTime()
    );
  };

  const fetchDeployments = async (env: Environment) => {
    try {
      setLoading(true);
      setError(null);
      const response = await fetch(`/release/all/${env}`);
      if (!response.ok) {
        throw new Error(`HTTP Error: ${response.status}`);
      }
      const data: ApiResponse = await response.json();
      setDeployments(data.results);
      setFilteredDeployments(getLatestDeployments(data.results));
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown error');
      console.error('Error fetching data:', err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchDeployments(selectedEnv);
  }, []);

  const handleEnvChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    const newEnv = event.target.value as Environment;
    setSelectedEnv(newEnv);
    fetchDeployments(newEnv);
  };

  const formatDate = (dateString: string) => {
    if (dateString === '0001-01-01T00:00:00') return '-';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const getEnvironmentBadge = (env: string) => {
    const colors: Record<string, string> = {
      PROD: '#dc3545',
      STAGE: '#ffc107',
      TEST: '#28a745'
    };
    return colors[env] || '#6c757d';
  };

  // Helper to generate GitHub URL
  // If your projects map to different repos, you can add logic here based on dep.project
  const getGitHubUrl = (commitHash: string, projectName?: string) => {
    // Example: If you have different repos per project, you could do:
    // let repo = projectName.toLowerCase().replace(' ', '-');
    // if (projectName === 'BE') repo = 'backend-repo';

    return `https://github.com/$${GITHUB_ORG}/$${GITHUB_REPO}/commit/${commitHash}`;
  };

  return (
    <div className="App">
      <header className="App-header">
        <h1>🚀 Deploy Tracker</h1>
        <div className="controls">
          <label htmlFor="env-select">Environment:</label>
          <select 
            id="env-select" 
            value={selectedEnv} 
            onChange={handleEnvChange}
            disabled={loading}
          >
            <option value="PROD">PROD</option>
            <option value="STAGE">STAGE</option>
            <option value="TEST">TEST</option>
          </select>
          <button 
            onClick={() => fetchDeployments(selectedEnv)} 
            disabled={loading}
            className="refresh-btn"
          >
            {loading ? 'Loading...' : 'Refresh'}
          </button>
        </div>
      </header>

      <main className="App-main">
        {!loading && !error && (
          <div className="stats">
            <span>Showing: {filteredDeployments.length} / Total: {deployments.length}</span>
          </div>
        )}

        {loading && <div className="loading">Loading data...</div>}

        {error && <div className="error">❌ Error: {error}</div>}

        {!loading && !error && filteredDeployments.length === 0 && (
          <div className="no-data">No deployments found for {selectedEnv}</div>
        )}

        {!loading && !error && filteredDeployments.length > 0 && (
          <table className="deployment-table">
            <thead>
              <tr>
                <th>Customer</th>
                <th>Project</th>
                <th>Environment</th>
                <th>Branch</th>
                <th>Commit</th>
                <th>Deployer</th>
                <th>Release Date</th>
              </tr>
            </thead>
            <tbody>
              {filteredDeployments.map((dep, index) => {
                const commitLink = getGitHubUrl(dep.commit, dep.project);
                return (
                  <tr key={index}>
                    <td>{dep.customer}</td>
                    <td>{dep.project}</td>
                    <td>
                      <span 
                        className="badge"
                        style={{ backgroundColor: getEnvironmentBadge(dep.environment) }}
                      >
                        {dep.environment}
                      </span>
                    </td>
                    <td>{dep.branch}</td>
                    <td className="commit">
                      <a 
                        href={commitLink} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        title={`View commit ${dep.commit}`}
                        className="commit-link"
                      >
                        {dep.commit.substring(0, 7)} ↗
                      </a>
                    </td>
                    <td>{dep.user}</td>
                    <td>{formatDate(dep.releaseDate)}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </main>
    </div>
  );
}

export default App;
